--
-- Table structure for table `newsletter_items`
--

DROP TABLE IF EXISTS `newsletter_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `newsletter_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `newsletter_id` bigint unsigned NOT NULL,
  `portal` varchar(120) DEFAULT NULL,
  `news_date` date DEFAULT NULL,
  `title` text NOT NULL,
  `description` text,
  `link_url` varchar(500) DEFAULT NULL,
  `pdf_path` varchar(255) DEFAULT NULL,
  `sort_order` int NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `category_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_newsletter_sort` (`newsletter_id`,`sort_order`),
  KEY `fk_item_category` (`category_id`),
  CONSTRAINT `fk_item_category` FOREIGN KEY (`category_id`) REFERENCES `newsletter_categories` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_item_newsletter` FOREIGN KEY (`newsletter_id`) REFERENCES `newsletters` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1767 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `newsletter_items`
--

LOCK TABLES `newsletter_items` WRITE;
/*!40000 ALTER TABLE `newsletter_items` DISABLE KEYS */;
INSERT INTO `newsletter_items` VALUES (4,4,'BNAmericas','2026-02-19','HIF Global e German eFuel One assinam acordo preliminar de compra de e-metanol','HIF Global, a empresa líder em e-Combustíveis, e a companhia alemã German eFuel One, pioneira em soluções de energia limpa, assinaram um acordo preliminar (Heads of Agreement - HoA) para o fornecimento de longo prazo de e-Metanol da carteira de projetos da HIF Global.','https://www.bnamericas.com/pt/noticias/hif-global-e-german-efuel-one-assinam-acordo-preliminar-de-compra-de-e-metanol',NULL,0,'2026-02-20 16:58:00',NULL),(5,4,'Canal Energia','2026-02-19','Produção de Hidrogênio de Baixo Carbono cresce e pode chegar a 65,3 mtpa em 2030','Relatório da GlobalData sobre o mercado de hidrogênio de baixo carbono mostra que a tendência de crescimento energético mudou nos dois últimos anos, com a produção aumentando para 0,84 milhão de toneladas por ano em 2024.','https://www.canalenergia.com.br/noticias/53339576/53339576','/uploads/pdfs/b66042dcc0bb59163251fe06783cd112.pdf',1,'2026-02-20 16:58:01',NULL),(6,4,'TN Petroleo','2026-02-20','Paulo Alvarenga é nomeado CEO da TKMS Brazil','Desde 2 de fevereiro de 2026, Paulo Alvarenga assumiu a posição de CEO da TKMS Brazil. Com mais de 13 anos de experiência na thyssenkrupp, Alvarenga deixa sua função de liderança corporativa no nível do grupo para liderar duas operações estratégicas em um momento decisivo na transformação do conglomerado industrial alemão.','https://tnpetroleo.com.br/noticia/paulo-alvarenga-e-nomeado-ceo-da-tkms-brazil/',NULL,2,'2026-02-20 16:58:01',NULL),(7,5,'Movimento Econômico','2026-02-23','Projetos alinhados à Nova Indústria Brasil terão R$ 3,3 bi para inovação','No total, serão 13 editais de subvenção econômica para inovação em cadeias agroindustriais, saúde, infraestrutura, transformação digital, transição energética e defesa nacional','https://movimentoeconomico.com.br/tecnologia/2026/02/23/projetos-alinhados-a-nova-industria-brasil-terao-r-33-bi-para-inovacao/',NULL,0,'2026-02-23 09:32:39',NULL),(8,5,'Info Negócios','2026-02-23','A HIF Global fechou um acordo na Alemanha para o fornecimento de 100.000 toneladas por ano de e-Metanol (e projeta exportações da região de Paysandú).','A empresa assinou um acordo preliminar com a alemã eFuel One para abastecer o mercado europeu com e-metanol. Parte do volume planejado viria do projeto HIF Paysandú, no Uruguai','https://infonegocios.biz/nota-principal/hif-global-cerro-acuerdo-en-alemania-por-100-000-toneladas-anuales-de-e-metanol-y-proyecta-exportaciones-desde-paysandu',NULL,1,'2026-02-23 09:32:39',NULL),(9,5,'Brazil Economy','2026-02-22','Alemães intensificam agenda no País e defendem relação confiável em meio a Trump','Visita do deputado Rainer Rothfuss reforça aposta em parceria estratégica entre Brasil e Alemanha com foco em energia limpa e mobilidade a hidrogênio','https://brazileconomy.com.br/economia/2026/02/alemaes-intensificam-agenda-no-brasil-e-defendem-relacoes-confiaveis-em-meio-a-trump/',NULL,2,'2026-02-23 09:32:39',NULL),(10,5,'Jornal do Comércio do Ceará','2026-02-22','Acordo UE–Mercosul abre caminho para investimentos europeus em energia limpa e data centers no Ceará','Embora os Estados Unidos ainda sejam o principal parceiro comercial do Ceará, o acordo UE–Mercosul abre espaço para a diversificação de mercados, especialmente em áreas como hidrogênio verde, energia renovável, tecnologia e infraestrutura','https://jcce.com.br/acordo-ue-mercosul-abre-caminho-para-investimentos-europeus-em-energia-limpa-e-data-centers-no-ceara/',NULL,3,'2026-02-23 09:32:39',NULL),(11,5,'Jornal Portuário','2026-02-22','Comitiva de Suape inicia agenda estratégica na ASEAN em busca de expansão global','Entre os destaques da agenda estão a construção do terminal de cargas e contêineres da APM Terminals, a implantação de duas fábricas de e-metanol e os avanços na agenda de transição energética','https://jornalportuario.com.br/noticia/2070/comitiva-de-suape-inicia-agenda-estrategica-na-asean-em-busca-expansao-global',NULL,4,'2026-02-23 09:32:39',NULL),(12,5,'Diário de Minas','2026-02-22','BioTech Fair 2026 coloca o Brasil no centro da transição energética global','Com formato internacional, a BioTech Fair integra feira de negócios, congresso técnico e seis eventos segmentados, consolidando-se como o único evento no Brasil que reúne, em um só espaço, todas as fontes renováveis de energia, como biodiesel, biomassa, biogás, hidrogênio verde, etanol e soluções baseadas em resíduos sólidos urbanos','https://diariodeminas.com.br/biotech-fair-2026-coloca-o-brasil-no-centro-da-transicao-energetica-global/',NULL,5,'2026-02-23 09:32:39',NULL),(13,5,'Canal Executivo','2026-02-20','Paulo Alvarenga é nomeado CEO da TKMS Brazil','Com mais de 13 anos de experiência na thyssenkrupp, Alvarenga deixa sua função de liderança corporativa no nível do grupo para liderar duas operações estratégicas em um momento decisivo na transformação do conglomerado industrial alemão','https://canalexecutivoblog.wordpress.com/2026/02/20/paulo-alvarenga-e-nomeado-ceo-da-tkms-brazil/',NULL,6,'2026-02-23 09:32:39',NULL),(14,5,'Tv Times Brasil','2026-02-22','Energia limpa: vetor de crescimento','Matriz renovável gera potencial para investimento','https://kn-media-resources-public.s3.us-east-1.wasabisys.com/tv/1320170/2026/02/23/20260223_004256-20260223_004756.mp4',NULL,7,'2026-02-23 09:32:39',NULL),(15,5,'Correio Braziliense','2026-02-23','Pesquisadores produzem hidrogênio limpo usando água e luz solar','Apesar do potencial, a produção de hidrogênio verde em escala eficiente e econômica ainda representa um desafio. Métodos tradicionais, como a eletrólise, esbarram em custos elevados e limitações de rendimento. Em busca de alternativas, pesquisadores da Universidade de Sydney, na Austrália, desenvolveram uma técnica que utiliza metais líquidos e luz solar para produzir hidrogênio a partir de água doce ou salgada. O estudo foi publicado na revista Nature Communications e apresenta um